import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsNull() {
        // Create CSVFormat instance with escapeCharacter null using DEFAULT
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);
        assertFalse(format.isEscapeCharacterSet(), "Escape character should not be set when null");
    }

    @Test
    void testIsEscapeCharacterSetWhenEscapeCharacterIsSet() {
        // Create CSVFormat instance with escapeCharacter set to BACKSLASH
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        assertTrue(format.isEscapeCharacterSet(), "Escape character should be set when non-null");
    }
}
